-- Benthyo seed data (idempotent)
-- 50 Mediterranean dive sites, 200 marine species, 5 Italian operators, 10 badges

BEGIN;

ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  location = EXCLUDED.location,
  depth_min = EXCLUDED.depth_min,
  depth_max = EXCLUDED.depth_max,
  updated_at = now();

-- NOTE: external taxon IDs (inat_taxon_id / worms_id / gbif_taxon_key) are
-- intentionally NOT seeded here. The previous hardcoded values were fabricated
-- (duplicated / sequential placeholders) and broke photo enrichment. They are
-- now resolved from live APIs by the ETL steps (species-seed, worms,
-- inat-taxon-lookup). This seed only provides curated names, which the ETL
-- never overwrites (see COALESCE below).
ON CONFLICT (scientific_name) DO UPDATE SET
  common_name = COALESCE(species.common_name, EXCLUDED.common_name),
  common_name_it = COALESCE(species.common_name_it, EXCLUDED.common_name_it),
  common_name_es = COALESCE(species.common_name_es, EXCLUDED.common_name_es),
  family = COALESCE(species.family, EXCLUDED.family),
  genus = COALESCE(species.genus, EXCLUDED.genus),
  updated_at = now();

ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  email = EXCLUDED.email,
  phone = EXCLUDED.phone,
  website = EXCLUDED.website,
  updated_at = now();

SELECT o.id, ds.id, true FROM operators o, dive_sites ds
WHERE o.slug = 'diving-center-ustica' AND ds.slug = 'ustica-secca-colobbara'
ON CONFLICT (operator_id, dive_site_id) DO UPDATE SET is_primary = EXCLUDED.is_primary;
SELECT o.id, ds.id, true FROM operators o, dive_sites ds
WHERE o.slug = 'portofino-divers' AND ds.slug = 'ustica-punta-gavazzi'
ON CONFLICT (operator_id, dive_site_id) DO UPDATE SET is_primary = EXCLUDED.is_primary;
SELECT o.id, ds.id, true FROM operators o, dive_sites ds
WHERE o.slug = 'elba-sub' AND ds.slug = 'ustica-grotta-gamberi'
ON CONFLICT (operator_id, dive_site_id) DO UPDATE SET is_primary = EXCLUDED.is_primary;
SELECT o.id, ds.id, true FROM operators o, dive_sites ds
WHERE o.slug = 'sardinia-dive-experience' AND ds.slug = 'portofino-cristo-abissi'
ON CONFLICT (operator_id, dive_site_id) DO UPDATE SET is_primary = EXCLUDED.is_primary;
SELECT o.id, ds.id, true FROM operators o, dive_sites ds
WHERE o.slug = 'scuba-academy-siracusa' AND ds.slug = 'portofino-punta-faro'
ON CONFLICT (operator_id, dive_site_id) DO UPDATE SET is_primary = EXCLUDED.is_primary;

ON CONFLICT (code) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  criteria_type = EXCLUDED.criteria_type,
  criteria_value = EXCLUDED.criteria_value,
  tier = EXCLUDED.tier;

COMMIT;
